# CodeLens benchmark: correct binary search case 0-0
def process_values_0(data_item_0, target_number_0):
    low = 0
    high = len(data_item_0) - 1
    while low <= high:
        mid = (low + high) // 2
        if data_item_0[mid] == target_number_0:
            return mid
        if data_item_0[mid] < target_number_0:
            low = mid + 1
        else:
            high = mid - 1
    return -1

position = process_values_0([1, 3, 5, 7, 9], 7)
print(position)

# CodeLens benchmark: correct linear search case 1-0
def solve_1(data_item_1, target_target_1):
    for position in range(len(data_item_1)):
        if data_item_1[position] == target_target_1:
            return position
    return -1

answer = solve_1([4, 8, 12, 16], 12)
print(answer)

